mapper.insert:


    SELECT COALESCE(MAX(ent_id)::integer,0)+1
    FROM book



INSERT INTO book (
                   ent_id
                 ,title
                 ,author
                 ,publisher
                 ,pub_date
                 ,reg_date
                 ,lib_no
                 ,mark_no
                 ,posi
                 ,clas
                 ,auth
                 ,vol
                 ,price
                 ,state
                 ,book_id
                 ,book_sec
                 ,book_type
                 ,book_no
)
values (
        #{bookNo}
       ,#{title}
       ,#{author}
       ,#{publisher}
       ,#{pubDate}
